mapper.select:
SELECT kp.id, kp.title, kp.content, kp.view_count, kp.depth, kp.root_id, kp.parent_id, kp.created_at, u.nickname, u.username, u.id AS user_id, (SELECT COUNT(*) FROM knowledge_posts b WHERE b.root_id = kp.id AND b.parent_id IS NOT NULL) AS branch_count FROM knowledge_posts kp JOIN users u ON kp.user_id = u.id WHERE kp.parent_id IS NULL
AND (kp.title LIKE CONCAT('%', #{keyword}, '%') OR kp.content LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY kp.created_at DESC LIMIT #{offset}, #{pageSize}
